 3→const posthogKey = import.meta.env.VITE_POSTHOG_KEY as string | undefined
 4→const posthogHost = import.meta.env.VITE_POSTHOG_HOST as string | undefined
 5→
 6→export const posthogEnabled = Boolean(posthogKey)
 7→
 8→if (!posthogEnabled) {
 9→  console.info('Missing VITE_POSTHOG_KEY — PostHog analytics is disabled.')
10→} else {
11→  posthog.init(posthogKey!, {
12→    api_host: posthogHost || 'https://us.i.posthog.com',
13→    capture_pageview: false,
14→    capture_pageleave: true,
15→    autocapture: false,
16→    respect_dnt: true,
17→    persistence: 'localStorage',
18→    loaded: (ph) => {
19→      if (import.meta.env.DEV) ph.debug()
20→    },
21→  })
22→}
23→
24→if (posthogEnabled) {
25→  window.onerror = (_message, _source, _lineno, _colno, error) => {
26→    if (error) {
27→      posthog.capture('$exception', {
28→        $exception_message: error.message,
29→        $exception_type: error.name,
30→        $exception_stack_trace_raw: error.stack,
31→        $exception_source: 'window_onerror',
32→      })
33→    }
34→  }
35→
36→  window.onunhandledrejection = (event: PromiseRejectionEvent) => {
37→    const error = event.reason instanceof Error ? event.reason : new Error(String(event.reason))
38→    posthog.capture('$exception', {
39→      $exception_message: error.message,
40→      $exception_type: error.name,
41→      $exception_stack_trace_raw: error.stack,
42→      $exception_source: 'unhandled_rejection',
43→    })
44→  }
45→}
46→
47→export { posthog }
